const fs = require('fs');

// Read queue
let q = { cycles: 0, leads: [] };
try { q = JSON.parse(fs.readFileSync('/tmp/lead_queue.json', 'utf8')); } catch(e) {}

// Read DMs
let dms = [];
try { dms = JSON.parse(fs.readFileSync('/tmp/lead_dms.json', 'utf8')); } catch(e) {}

// Count by status
const total = q.leads.length;
const newLeads = q.leads.filter(l => l.status === 'new').length;
const processing = q.leads.filter(l => l.status === 'processing').length;
const dmSent = q.leads.filter(l => l.status === 'dm_sent').length;

// Leads with email (qualifiable)
const withEmail = q.leads.filter(l => l.email && l.email.includes('@')).length;

// Build response matching old EC2 format
const status = {
  success: true,
  pipeline: {
    cycles_run: q.cycles || 0,
    last_cycle: new Date().toISOString(),
    current_phase: dmSent > 0 ? 'sending_dm' : (processing > 0 ? 'processing' : (newLeads > 0 ? 'finding_leads' : 'idle')),
    pipeline_active: true,
    errors: [],
    leads_found_today: 0,  // simplified - no daily tracking
    total_leads_found: total,
    total_onboarded: dmSent,
    total_dms_sent: dms.filter(d => d.type === 'initial').length,
    total_followups_sent: dms.filter(d => d.type === 'followup').length,
    queue: {
      total: total,
      new: newLeads,
      processing: processing,
      dm_sent: dmSent,
      with_email: withEmail
    }
  },
  n8n: {
    workflows: {
      find_leads: 'active',
      qualify: 'active',
      send_dm: 'active',
      follow_up: 'active',
      watchdog: 'active'
    }
  }
};

return status;
